using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);
var errors = build.FindChildrenRecursive<Error>();
var warnings = build.FindChildrenRecursive<Warning>();

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

Console.WriteLine("=== ALL ERRORS ===");
foreach (var e in errors)
{
    var parent = e.Parent;
    string projectName = "unknown";
    while (parent != null)
    {
        if (parent is Project p) { projectName = p.Name; break; }
        parent = parent.Parent;
    }
    Console.WriteLine($"[{projectName}] {e.Code}: {e.Message}");
    if (!string.IsNullOrEmpty(e.File))
        Console.WriteLine($"  File: {e.File} Line: {e.LineNumber}");
    Console.WriteLine();
}

Console.WriteLine("=== ALL WARNINGS ===");
foreach (var w in warnings)
{
    var parent = w.Parent;
    string projectName = "unknown";
    while (parent != null)
    {
        if (parent is Project p) { projectName = p.Name; break; }
        parent = parent.Parent;
    }
    Console.WriteLine($"[{projectName}] {w.Code}: {w.Message}");
    if (!string.IsNullOrEmpty(w.File))
        Console.WriteLine($"  File: {w.File} Line: {w.LineNumber}");
}

Console.WriteLine();
Console.WriteLine("=== PROJECT DEPENDENCY GRAPH ===");
var projects = build.FindChildrenRecursive<Project>();
foreach (var p in projects)
{
    Console.WriteLine($"Project: {p.Name} (Succeeded={p.Succeeded})");
}
