using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);
Console.WriteLine($"BUILD SUCCEEDED: {build.Succeeded}\n");

// Get all errors
Console.WriteLine("=== ALL ERRORS (with full context) ===");
foreach (var node in build.FindChildrenRecursive<Error>())
{
    Console.WriteLine($"Code:    {node.Code}");
    Console.WriteLine($"Text:    {node.ToString()}");
    Console.WriteLine($"File:    {node.File}");
    Console.WriteLine($"Line:    {node.LineNumber}, Col: {node.ColumnNumber}");

    // Walk up to find Task and Target
    var p = node.Parent;
    while (p != null)
    {
        if (p is Task t) Console.WriteLine($"Task:    {t.Name}");
        if (p is Target tgt) Console.WriteLine($"Target:  {tgt.Name}");
        if (p is Project proj) { Console.WriteLine($"Project: {proj.Name}"); break; }
        p = p.Parent;
    }
    Console.WriteLine();
}

// Check for build failures / dependency failures
Console.WriteLine("=== PROJECT BUILD RESULTS (Build target only) ===");
var targets = build.FindChildrenRecursive<Target>().Where(t => t.Name == "Build" || t.Name == "CoreCompile");
foreach (var t in targets)
{
    var proj = t.Parent;
    while (proj != null && !(proj is Project)) proj = proj.Parent;
    var projName = proj is Project pp ? pp.Name : "?";
    Console.WriteLine($"  {projName} -> {t.Name}: Succeeded={t.Succeeded}");
}
