using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);

// Check if Api even got to compile
Console.WriteLine("=== Api.csproj targets that ran ===");
var apiProjects = build.FindChildrenRecursive<Project>().Where(p => p.Name == "Api.csproj");
foreach (var proj in apiProjects)
{
    var targets = proj.FindChildrenRecursive<Target>();
    foreach (var t in targets)
    {
        Console.WriteLine($"  Target: {t.Name} Succeeded={t.Succeeded}");
    }
    Console.WriteLine($"  --- (end of {proj.Title})");
}

Console.WriteLine("\n=== Services.csproj targets that ran ===");
var svcProjects = build.FindChildrenRecursive<Project>().Where(p => p.Name == "Services.csproj");
foreach (var proj in svcProjects)
{
    var targets = proj.FindChildrenRecursive<Target>();
    foreach (var t in targets)
    {
        if (t.Name == "CoreCompile" || t.Name == "Build" || t.Name == "ResolveProjectReferences" || t.Name == "ResolveAssemblyReferences" || !t.Succeeded)
            Console.WriteLine($"  Target: {t.Name} Succeeded={t.Succeeded}");
    }
    Console.WriteLine($"  --- (end of {proj.Title})");
}

// Check the nuget restore results / packages referenced
Console.WriteLine("\n=== Package references per project ===");
foreach (var proj in build.FindChildrenRecursive<Project>().GroupBy(p => p.Name).Select(g => g.First()))
{
    Console.WriteLine($"\n{proj.Name}:");
    var items = proj.FindChildrenRecursive<Item>().Where(i => i.Name == "PackageReference" || i.Name == "ProjectReference");
    foreach (var item in items.Take(20))
    {
        Console.WriteLine($"  {item.Name}: {item.Text}");
    }
}
