{
    var p = task.Parent;
    while (p != null)
    {
        if (p is Project proj) { Console.WriteLine($"\nProject: {proj.Name}"); break; }
        p = p.Parent;
    }
    // Get command line from task properties
    foreach (var child in task.Children)
    {
        if (child is Property prop)
            Console.WriteLine($"  {prop.Name} = {prop.Value}");
        if (child is Message msg)
            Console.WriteLine($"  MSG: {msg}");
        if (child is Folder f)
        {
            Console.WriteLine($"  Folder: {f.Name}");
            foreach (var fc in f.Children.Take(50))
            {
                if (fc is Property fp) Console.WriteLine($"    {fp.Name} = {fp.Value}");
                else if (fc is Item fi) Console.WriteLine($"    Item: {fi.Name} = {fi}");
                else Console.WriteLine($"    {fc.GetType().Name}: {fc}");
            }
        }
    }
}

// Also search for embedded source content using SourceFile
