foreach (var sf in build.FindChildrenRecursive<SourceFile>())
{
    Console.WriteLine($"SourceFile: {sf.Name}");
}

// Search for any file content
Console.WriteLine("\n=== EmbeddedContent ===");
foreach (var node in build.FindChildrenRecursive<TextNode>())
{
    var s = node.ToString();
    if (s.Contains("UserService") || s.Contains("Models.cs") || s.Contains("Program.cs"))
        Console.WriteLine($"TextNode: {s}");
}
